insert into public.events (title, description, date, time, starts_at, ends_at, venue, venue_name, neighborhood, venue_address, latitude, longitude, category, tags, price_min, price_max, is_free, source, external_url, url, image_url, external_id, is_recurring, timezone, status) values
('France vs. Spain — World Cup Semifinal Watch Party', $d$Official FIFA World Cup 2026 Fan Zone on the National Mall. France vs. Spain semifinal at 3PM ET on giant screens. Includes live match viewing, interactive exhibits, food, music, cultural showcases, and family-friendly activations. Open as late as 1AM for select games. France is today's Bastille Day home team; all of DC is celebrating the match.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T23:59:00+00', 'FIFA World Cup Fan Zone', 'FIFA World Cup Fan Zone', 'National Mall', 'National Mall between 3rd and 4th Streets NW (near U.S. Capitol), Washington, DC 20024', 38.8895, -77.0082, 'festivals', ARRAY['world cup','soccer','free','outdoor','family-friendly','france','spain','bastille day']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://freedom250.org/news/freedom-250-announces-fifa-world-cup-2026-fan-zone-washington-dc', 'https://freedom250.org/news/freedom-250-announces-fifa-world-cup-2026-fan-zone-washington-dc', 'https://washington.org/sites/default/files/2026-06/hero_fifa-fan-zone.png', 'wc2026_fanzone_nationalmall_20260714', FALSE, 'America/New_York', 'published'),
('France vs. Spain Semifinal Watch Party — Bastille Day at Pastis', $d$French bistro Pastis combines Bastille Day celebrations with the France vs. Spain World Cup semifinal. Specials include $1 oysters, rosé, cocktails, and happy hour deals while Les Bleus take the pitch. Festive Parisian atmosphere with food and drink specials.$d$, '2026-07-14', '2:00 PM', '2026-07-14T18:00:00+00', '2026-07-14T21:00:00+00', 'Pastis DC', 'Pastis DC', 'NoMa/Union Market', 'Union Market, 1309 5th St NE, Washington, DC 20002', 38.9087, -76.9956, 'festivals', ARRAY['world cup','soccer','france','bastille day','happy hour','oysters','outdoor']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://pastisdc.com/', 'https://pastisdc.com/', 'https://images.axios.com/axXXGs3JEO7SE_3gyf3gbWlE-zM=/0x99:2270x1376/1366x768/2026/07/13/1783972679519.jpeg', 'wc2026_pastis_unionmarket_20260714', FALSE, 'America/New_York', 'published'),
('France vs. Spain Semifinal + Bastille Day at Bonne Vie', $d$Rooftop watch party for the France vs. Spain World Cup semifinal at this steak frites restaurant on 14th Street. Match on rooftop bar with happy hour specials from 4–7PM and a $45 signature Bastille Day prix-fixe dinner menu.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T23:00:00+00', 'Bonne Vie', 'Bonne Vie', 'U Street', '1802 14th St NW, Washington, DC 20009', 38.9169, -77.0322, 'festivals', ARRAY['world cup','soccer','rooftop','france','bastille day','happy hour','prix-fixe']::text[], 0, 45, TRUE, 'world_cup_2026', 'https://www.bonneviedc.com/', 'https://www.bonneviedc.com/', NULL, 'wc2026_bonnevie_ustreet_20260714', FALSE, 'America/New_York', 'published'),
('France vs. Spain Semifinal Watch Party at Penn Social', $d$Penn Social is one of DC's biggest World Cup destinations, hosting the France vs. Spain semifinal with giant screens throughout the massive sports bar. Specials include $6 Kronenbourg beers and $35 Domaine wine bottles. RSVP encouraged. Also the official France fan HQ for the tournament.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T23:00:00+00', 'Penn Social', 'Penn Social', 'Penn Quarter', '801 E St NW, Washington, DC 20004', 38.8952, -77.0235, 'festivals', ARRAY['world cup','soccer','france','spain','sports bar','beer specials']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.pennsocialdc.com/', 'https://www.pennsocialdc.com/', 'https://washington.org/sites/default/files/2023-10/Crop%20for%20Web%20-%202023-10-05T141858.008.jpg', 'wc2026_pennsocial_pennquarter_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal Watch Party at The Wharf', $d$Catch the France vs. Spain World Cup semifinal on the 14-foot jumbotron on Pearl Street at The Wharf. Free outdoor watch party with food and drinks from Colada Shop, Kirwan's, Pink Tiger, and other waterfront restaurant partners. Opens one hour before kickoff. Rain or shine.$d$, '2026-07-14', '2:00 PM', '2026-07-14T18:00:00+00', '2026-07-14T22:00:00+00', 'The Wharf Summer of Soccer Watch Zone', 'The Wharf Summer of Soccer Watch Zone', 'Southwest/The Wharf', 'Pearl Street at The Wharf, 760 Maine Ave SW, Washington, DC 20024', 38.8786, -77.0194, 'festivals', ARRAY['world cup','soccer','outdoor','waterfront','free','jumbotron','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.wharfdc.com/fifa2026/', 'https://www.wharfdc.com/fifa2026/', 'https://washington.org/sites/default/files/2026-06/HERO_WorldCup-The-Wharf%20copy.png', 'wc2026_wharf_pearls_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Hi-Lawn Union Market', $d$Rooftop turf soccer pitch with giant LED screens and capacity for up to 1,000 fans. Soccer-themed trivia, DJs, and entertainment. Watch France vs. Spain in the semifinal with panoramic views over NoMa. Kid-friendly during daytime hours. Free with reservations.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Hi-Lawn at Union Market', 'Hi-Lawn at Union Market', 'NoMa/Union Market', '1309 5th St NE, Washington, DC 20002', 38.909, -76.9951, 'festivals', ARRAY['world cup','soccer','rooftop','free','family-friendly','DJ','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://unionmarketdc.com/soccer/', 'https://unionmarketdc.com/soccer/', 'https://washington.org/sites/default/files/2026-06/union-market-la-cosecha-world-cup.jpeg', 'wc2026_hilawn_unionmarket_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal Watch Party at La Cosecha', $d$Latin American food hall showing the France vs. Spain semifinal on large screens with themed pop-ups and tournament specials. Food and drinks from Cafe Unido, Grand Cata wines, tacos, arepas, and pupusas available. Games after 10PM will not be screened. Open to the public.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'La Cosecha', 'La Cosecha', 'NoMa/Union Market', '1280 4th St NE, Washington, DC 20002', 38.9084, -76.9968, 'festivals', ARRAY['world cup','soccer','latin food','free','france','spain','food hall']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://unionmarketdc.com/soccer/', 'https://unionmarketdc.com/soccer/', NULL, 'wc2026_lacosecha_unionmarket_20260714', FALSE, 'America/New_York', 'published'),
('France vs. Spain Semifinal at Hook Hall', $d$Hook Hall screens the France vs. Spain semifinal on 20-foot screens and TVs throughout the venue. The $19.99 ticket includes food and drinks themed around the competing nations. One of DC's most festive World Cup venues.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Hook Hall', 'Hook Hall', 'Petworth/Parkview', '3400 Georgia Ave NW, Washington, DC 20010', 38.9375, -77.0222, 'festivals', ARRAY['world cup','soccer','france','spain','food included','ticketed','20-foot screen']::text[], 20, 20, FALSE, 'world_cup_2026', 'https://www.hookhall.com/', 'https://www.hookhall.com/', NULL, 'wc2026_hookhall_petworth_20260714', FALSE, 'America/New_York', 'published'),
('France vs. Spain Semifinal at Madhatter', $d$DC staple since 1982. Madhatter screens all World Cup matches with multiple screens and private dining options. Country-themed viewing parties with drink specials: $5 Mich Ultra and Madhatter Light drafts, $6 NÜTRLs, $20 pitchers, $30 NÜTRL buckets, $40 beer towers.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Madhatter', 'Madhatter', 'Dupont Circle', '1319 Connecticut Ave NW, Washington, DC 20036', 38.9099, -77.0432, 'festivals', ARRAY['world cup','soccer','dupont circle','drink specials','france','spain','bar']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://madhatterdc.com/', 'https://madhatterdc.com/', NULL, 'wc2026_madhatter_dupont_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Wunder Garten x Volo Sports', $d$Giant indoor and outdoor screenings at Wunder Garten for the France vs. Spain semifinal. Themed entertainment, giveaways, fan competitions, specialty international brews. Embassy collaborations and cultural celebrations throughout. Free and open to the public; VIP options available.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Wunder Garten', 'Wunder Garten', 'Shaw/Mount Vernon Triangle', '1101 New York Ave NW, Washington, DC 20005', 38.9025, -77.0238, 'festivals', ARRAY['world cup','soccer','beer garden','free','outdoor','international','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.wundergarten.com/', 'https://www.wundergarten.com/', NULL, 'wc2026_wundergarten_shaw_20260714', FALSE, 'America/New_York', 'published'),
('Spain Watch Party at Jaleo — World Cup Semifinal', $d$José Andrés' Spanish tapas restaurant transforms into a soccer bar for Spain's World Cup matches. Official Spain fan watch party for the France vs. Spain semifinal with food and drink specials. Festive atmosphere with tapas and Spanish wines while cheering on La Roja.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Jaleo', 'Jaleo', 'Penn Quarter', '480 7th St NW, Washington, DC 20004', 38.8951, -77.0217, 'festivals', ARRAY['world cup','soccer','spain','tapas','jose andres','penn quarter']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.jaleo.com/event/all-spain-matches-all-in-one-place/', 'https://www.jaleo.com/event/all-spain-matches-all-in-one-place/', NULL, 'wc2026_jaleo_pennquarter_20260714', FALSE, 'America/New_York', 'published'),
('Spain Semifinal Watch Party at Casa Teresa', $d$Casa Teresa in The Square food hall is the Embassy of Spain's official watch-party venue for Spain's matches. The France vs. Spain semifinal is shown on projectors with food and drink specials. Festive atmosphere with Spanish fans. One of the best spots in DC for Spain supporters.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Casa Teresa (The Square Food Hall)', 'Casa Teresa (The Square Food Hall)', 'Penn Quarter', '800 F St NW, Washington, DC 20004', 38.8959, -77.0231, 'festivals', ARRAY['world cup','soccer','spain','embassy','food hall','penn quarter']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.instagram.com/p/DavPNKmpSBx/', 'https://www.instagram.com/p/DavPNKmpSBx/', NULL, 'wc2026_casateresa_pennquarter_20260714', FALSE, 'America/New_York', 'published'),
('Bastille Day + France vs. Spain Watch Party at Lady Madison', $d$Free Parisian-style summer soirée celebrating Bastille Day and the France vs. Spain World Cup semifinal. Sip rosé, enjoy French-inspired bites, and watch the match with live music. Free to attend but RSVP encouraged. 21+.$d$, '2026-07-14', NULL, '2026-07-14T19:00:00+00', '2026-07-14T23:00:00+00', 'Lady Madison', 'Lady Madison', 'Downtown', '1177 15th St NW, Washington, DC 20005', 38.9031, -77.0366, 'festivals', ARRAY['world cup','soccer','france','bastille day','free','21+','live music','rosé']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.eventbrite.com/e/bastille-day-celebration-at-lady-madison-2026-tickets-1990823763468', 'https://ladymadisondc.com/', NULL, 'wc2026_ladymadison_downtown_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Sports & Social / Upstate FTW', $d$Wall-to-wall TVs with stadium-quality sound for the France vs. Spain World Cup semifinal. High-energy crowd built for groups and all-day hangouts. DJs, hosts, in-game moments, and World Cup-themed food menu. Drink specials: Heineken & Dos Equis buckets, beer towers.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Sports & Social / Upstate FTW', 'Sports & Social / Upstate FTW', 'U Street/Dupont Circle', '2012 P St NW, Washington, DC 20036', 38.9103, -77.0445, 'festivals', ARRAY['world cup','soccer','sports bar','DJ','beer specials','groups','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://sportsandsocial.com/dc/soccer-watch-party/', 'https://sportsandsocial.com/dc/soccer-watch-party/', NULL, 'wc2026_sportssocial_ustreet_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Metrobar', $d$Outdoor beer garden near Rhode Island Ave NE showing the France vs. Spain semifinal on a 20-foot screen with sound. Drink specials include cocktails, craft beers, and pizza. One of NoMa's favorite outdoor venues along the Metropolitan Branch Trail.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Metrobar', 'Metrobar', 'Brookland/NoMa', '640 Rhode Island Ave NE, Washington, DC 20002', 38.9215, -76.9949, 'festivals', ARRAY['world cup','soccer','outdoor','beer garden','20-foot screen','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://metrobardc.com/', 'https://metrobardc.com/', NULL, 'wc2026_metrobar_brookland_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Prost', $d$Authentic Bavarian beer hall with 11 German and Austrian drafts on tap, showing the France vs. Spain semifinal. Drink specials: $5 off 1-liter Spaten drafts, $6 NÜTRL, $10 Pretzel Knotchos. Great atmosphere for fans of both France and Spain.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Prost', 'Prost', 'Mount Vernon Square', '1314 9th St NW, Washington, DC 20001', 38.9057, -77.0215, 'festivals', ARRAY['world cup','soccer','beer hall','german beer','france','spain','drink specials']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://prostdc.com/', 'https://prostdc.com/', NULL, 'wc2026_prost_mountvernon_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Hall Pass', $d$Global Matchday HQ at Hall Pass showing the France vs. Spain semifinal with country-themed viewing parties, international beers, and street food-inspired menus. Every tournament match screened here with a festive, international crowd.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Hall Pass', 'Hall Pass', 'Penn Quarter/Chinatown', '700 H St NW, Washington, DC 20001', 38.8996, -77.0215, 'festivals', ARRAY['world cup','soccer','international','penn quarter','france','spain','beer']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://hallpassdc.com/', 'https://hallpassdc.com/', NULL, 'wc2026_hallpass_chinatown_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Boundary Stone', $d$Neighborhood pub vibe watching the France vs. Spain semifinal. Full tournament schedule screened here with $6 local drafts during all matches. A great low-key neighborhood option away from the big crowds.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Boundary Stone', 'Boundary Stone', 'Bloomingdale', '116 Rhode Island Ave NW, Washington, DC 20001', 38.9138, -77.0194, 'festivals', ARRAY['world cup','soccer','neighborhood bar','bloomingdale','$6 drafts','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.boundarystonedc.com/', 'https://www.boundarystonedc.com/', NULL, 'wc2026_boundarystone_bloomingdale_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Lucky Bar', $d$One of DC's longtime dedicated soccer bars showing the France vs. Spain World Cup semifinal. Known for its soccer-first crowd and passionate atmosphere. No reservations — first come, first served. The go-to spot for the soccer purist.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Lucky Bar', 'Lucky Bar', 'Dupont Circle', '1221 Connecticut Ave NW, Washington, DC 20036', 38.9093, -77.043, 'festivals', ARRAY['world cup','soccer','dupont circle','soccer bar','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.luckybardc.com/', 'https://www.luckybardc.com/', NULL, 'wc2026_luckybar_dupont_20260714', FALSE, 'America/New_York', 'published'),
('World Cup Semifinal at Grand Cata', $d$DC's Latin American wine bar hosts the France vs. Spain semifinal with curated wines, spirits, and small bites. Also has a second location inside La Cosecha at Union Market. International wine selection perfect for cheering on either squad.$d$, '2026-07-14', '2:00 PM', '2026-07-14T19:00:00+00', '2026-07-14T22:00:00+00', 'Grand Cata', 'Grand Cata', 'Shaw', '1926 9th St NW, Washington, DC 20001', 38.9118, -77.021, 'festivals', ARRAY['world cup','soccer','wine bar','shaw','latin american','france','spain']::text[], 0, NULL, TRUE, 'world_cup_2026', 'https://www.grandcata.com/', 'https://www.grandcata.com/', NULL, 'wc2026_grandcata_shaw_20260714', FALSE, 'America/New_York', 'published');
